$ErrorActionPreference = "Stop"
$PatchVersion = "1.4.6-r13-complete-merged-oneshot"
$DefaultSkin1080i = "E:\Kodi\portable_data\addons\skin.arctic.fuse.3\1080i"
$TempRoot = Join-Path $env:TEMP ("lrs_af3_r13_" + [guid]::NewGuid().ToString("N"))
New-Item -ItemType Directory -Force -Path $TempRoot | Out-Null

function Write-Utf8NoBom($Path, $Text) {
    [System.IO.File]::WriteAllText($Path, $Text, [System.Text.UTF8Encoding]::new($false))
}
function Decode-Base64Text($Payload) {
    return [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($Payload))
}
function Patch-SkinPath($Text, $SkinPath) {
    if ($SkinPath -and $SkinPath.Trim()) {
        $escaped = $SkinPath.Replace('`', '``').Replace('"', '`"')
        $Text = [regex]::Replace($Text, '\$DefaultSkin1080i\s*=\s*"[^"]+"', ('$DefaultSkin1080i = "' + $escaped + '"'))
        $Text = [regex]::Replace($Text, '\$Skin1080i\s*=\s*\$DefaultSkin1080i', '$Skin1080i = $DefaultSkin1080i')
    }
    return $Text
}
function Build-R7Script($SkinPath, $Mode) {
    $txt = Decode-Base64Text $PayloadR7
    $txt = Patch-SkinPath $txt $SkinPath
    $idx = $txt.IndexOf('while ($true) {')
    if ($idx -lt 0) { throw "Cannot locate r7 menu loop." }
    $head = $txt.Substring(0, $idx)
    if ($Mode -eq 'patch') {
        $tail = @'
Write-Host "[R7] Patch all / one-shot"
Patch-All
Check-Status
'@
    } elseif ($Mode -eq 'restore') {
        $tail = @'
Write-Host "[R7] Restore all / one-shot"
Remove-All
Check-Status
'@
    } else {
        $tail = @'
Write-Host "[R7] Check status / one-shot"
Check-Status
'@
    }
    return $head + "`r`n" + $tail
}
function Build-R11Script($SkinPath, $Mode) {
    $txt = Decode-Base64Text $PayloadR11
    $txt = Patch-SkinPath $txt $SkinPath
    $marker = 'Write-Host "============================================================"'
    $idx = $txt.LastIndexOf($marker)
    if ($idx -lt 0) { throw "Cannot locate r11 menu section." }
    $head = $txt.Substring(0, $idx)
    if ($Mode -eq 'patch') {
        $tail = @'
Write-Host "[R11] Patch Oscar BP fixed paths / one-shot"
Patch-All
'@
    } elseif ($Mode -eq 'restore') {
        $tail = @'
Write-Host "[R11] Restore Oscar hardcode / one-shot"
Restore-R9-DynamicOnlyToHardcode
Check-Status
'@
    } else {
        $tail = @'
Write-Host "[R11] Check Oscar BP status / one-shot"
Check-Status
'@
    }
    return $head + "`r`n" + $tail
}
function Run-TextScript($Name, $Text) {
    $path = Join-Path $TempRoot $Name
    Write-Utf8NoBom $path $Text
    Write-Host ""
    Write-Host "[RUN] $Name"
    Write-Host "------------------------------------------------------------"
    powershell.exe -NoProfile -ExecutionPolicy Bypass -File $path
    if ($LASTEXITCODE -ne 0) { throw "Patch script failed: $Name" }
}

$PayloadR7 = @'

'@
$PayloadR11 = @'

'@

try {
    Clear-Host
    Write-Host "============================================================"
    Write-Host "AF3 + LRS COMPLETE MERGED ONE-SHOT PATCH ($PatchVersion)"
    Write-Host "============================================================"
    Write-Host "Isi patch gabungan:"
    Write-Host "  - r7  : AF3/LRS rating slots, Hub active bridge, screensaver final clearlogo, progress-left"
    Write-Host "  - r11 : Oscar Best Picture fixed path: oscars.png / oscars_bp.png"
    Write-Host ""
    Write-Host "Default skin 1080i:"
    Write-Host "  $DefaultSkin1080i"
    Write-Host ""
    $custom = Read-Host "Tekan Enter untuk pakai default, atau masukkan full path folder 1080i"
    $skin = if ($custom.Trim()) { $custom.Trim() } else { $DefaultSkin1080i }

    Write-Host ""
    Write-Host "Pilih aksi:"
    Write-Host "  1. Patch complete / apply all"
    Write-Host "  2. Restore all"
    Write-Host "  3. Check status"
    Write-Host "  4. Exit"
    $choice = Read-Host "Masukkan pilihan [1/2/3/4]"
    switch ($choice) {
        '1' {
            Run-TextScript "R7-MERGED-ONESHOT.ps1" (Build-R7Script $skin 'patch')
            Run-TextScript "R11-OSCARS-BP-ONESHOT.ps1" (Build-R11Script $skin 'patch')
            Write-Host ""
            Write-Host "[OK] Complete merged patch applied."
        }
        '2' {
            Run-TextScript "R11-OSCARS-BP-RESTORE-ONESHOT.ps1" (Build-R11Script $skin 'restore')
            Run-TextScript "R7-MERGED-RESTORE-ONESHOT.ps1" (Build-R7Script $skin 'restore')
            Write-Host ""
            Write-Host "[OK] Complete merged restore applied."
        }
        '3' {
            Run-TextScript "R7-MERGED-STATUS-ONESHOT.ps1" (Build-R7Script $skin 'status')
            Run-TextScript "R11-OSCARS-BP-STATUS-ONESHOT.ps1" (Build-R11Script $skin 'status')
        }
        default { Write-Host "Exit." }
    }
} catch {
    Write-Host ""
    Write-Host "[ERROR] $($_.Exception.Message)"
    Write-Host "Tidak ada file yang ditimpa jika error terjadi sebelum tahap penulisan."
    exit 1
} finally {
    try { Remove-Item -LiteralPath $TempRoot -Recurse -Force -ErrorAction SilentlyContinue } catch {}
}
